import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  CardMedia,
  CardActions,
  Button,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  Rating,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  IconButton,
  useTheme,
} from '@mui/material';
import {
  Search as SearchIcon,
  FilterList as FilterIcon,
  Close as CloseIcon,
} from '@mui/icons-material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Doctors = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const [doctors, setDoctors] = useState([]);
  const [filteredDoctors, setFilteredDoctors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDepartment, setSelectedDepartment] = useState('');
  const [departments, setDepartments] = useState([]);
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);

  useEffect(() => {
    const fetchDoctors = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/doctors');
        console.log('Fetched doctors:', response.data);
        setDoctors(response.data);
        setFilteredDoctors(response.data);
      } catch (err) {
        console.error('Error fetching doctors:', err);
        setError('Failed to fetch doctors');
      } finally {
        setLoading(false);
      }
    };

    const fetchDepartments = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/departments');
        setDepartments(response.data);
      } catch (err) {
        console.error('Failed to fetch departments:', err);
      }
    };

    fetchDoctors();
    fetchDepartments();
  }, []);

  useEffect(() => {
    let filtered = [...doctors];

    // Apply search filter
    if (searchQuery) {
      filtered = filtered.filter(
        (doctor) =>
          doctor.userId.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
          doctor.specialization.toLowerCase().includes(searchQuery.toLowerCase()) ||
          doctor.department.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    // Apply department filter
    if (selectedDepartment) {
      filtered = filtered.filter(
        (doctor) => doctor.department === selectedDepartment
      );
    }

    setFilteredDoctors(filtered);
  }, [searchQuery, selectedDepartment, doctors]);

  const handleSearchChange = (e) => {
    setSearchQuery(e.target.value);
  };

  const handleDepartmentChange = (e) => {
    setSelectedDepartment(e.target.value);
  };

  const handleDoctorClick = (doctor) => {
    setSelectedDoctor(doctor);
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedDoctor(null);
  };

  const handleBookAppointment = () => {
    if (selectedDoctor) {
      navigate('/appointments', { state: { doctorId: selectedDoctor._id } });
    }
  };

  const defaultDoctorImage = 'https://img.freepik.com/free-photo/doctor-with-his-arms-crossed-white-background_1368-5790.jpg';

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Typography>Loading...</Typography>
      </Container>
    );
  }

  if (error) {
    return (
      <Container maxWidth="lg">
        <Typography color="error">{error}</Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography variant="h4" gutterBottom>
          Our Doctors
        </Typography>
        <Typography variant="body1" color="text.secondary">
          Find and book appointments with our experienced medical professionals
        </Typography>
      </Box>

      {/* Search and Filter Section */}
      <Box sx={{ mb: 4 }}>
        <Grid container spacing={2} alignItems="center">
          <Grid item xs={12} md={6}>
            <TextField
              fullWidth
              placeholder="Search doctors by name, specialization, or department"
              value={searchQuery}
              onChange={handleSearchChange}
              InputProps={{
                startAdornment: <SearchIcon sx={{ mr: 1, color: 'text.secondary' }} />,
                endAdornment: searchQuery && (
                  <IconButton size="small" onClick={() => setSearchQuery('')}>
                    <CloseIcon />
                  </IconButton>
                ),
              }}
            />
          </Grid>
          <Grid item xs={12} md={6}>
            <FormControl fullWidth>
              <InputLabel>Department</InputLabel>
              <Select
                value={selectedDepartment}
                onChange={handleDepartmentChange}
                label="Department"
              >
                <MenuItem value="">All Departments</MenuItem>
                {departments.map((dept) => (
                  <MenuItem key={dept._id} value={dept.name}>
                    {dept.name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
        </Grid>
      </Box>

      {/* Doctors Grid */}
      <Grid container spacing={3}>
        {loading ? (
          <Grid item xs={12}>
            <Typography variant="h6" align="center">Loading doctors...</Typography>
          </Grid>
        ) : filteredDoctors.length === 0 ? (
          <Grid item xs={12}>
            <Typography variant="h6" align="center" color="text.secondary">
              No doctors found
            </Typography>
          </Grid>
        ) : (
          filteredDoctors.map((doctor) => (
            <Grid item xs={12} sm={6} md={4} key={doctor._id}>
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  '&:hover': {
                    boxShadow: 6,
                    cursor: 'pointer',
                    transform: 'translateY(-4px)',
                    transition: 'transform 0.2s ease-in-out',
                  },
                }}
                onClick={() => handleDoctorClick(doctor)}
              >
                <CardMedia
                  component="img"
                  height="250"
                  image={doctor.profilePhoto || doctor.userId?.profilePhoto || defaultDoctorImage}
                  alt={doctor.userId?.name || 'Doctor'}
                  sx={{ 
                    objectFit: 'cover',
                    backgroundColor: 'grey.100'
                  }}
                />
                <CardContent sx={{ flexGrow: 1 }}>
                  <Typography gutterBottom variant="h6" component="h2">
                    {doctor.userId?.name || 'Doctor Name'}
                  </Typography>
                  <Typography variant="subtitle1" color="primary" gutterBottom>
                    {doctor.specialization}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" gutterBottom>
                    {doctor.department}
                  </Typography>
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                    <Rating value={doctor.ratings?.overall || 0} readOnly precision={0.5} />
                    <Typography variant="body2" color="text.secondary" sx={{ ml: 1 }}>
                      ({doctor.ratings?.totalReviews || 0} reviews)
                    </Typography>
                  </Box>
                  <Box sx={{ mt: 1 }}>
                    <Chip 
                      label={`${doctor.experience} years exp.`} 
                      size="small" 
                      sx={{ mr: 1, mb: 1 }}
                    />
                    <Chip 
                      label={`₹${doctor.consultationFee}`} 
                      color="primary" 
                      size="small" 
                      sx={{ mb: 1 }}
                    />
                  </Box>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>

      {/* Doctor Details Dialog */}
      <Dialog
        open={openDialog}
        onClose={handleCloseDialog}
        maxWidth="md"
        fullWidth
        scroll="paper"
      >
        {selectedDoctor && (
          <>
            <DialogTitle>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Typography variant="h5">{selectedDoctor.userId?.name}</Typography>
                <IconButton onClick={handleCloseDialog}>
                  <CloseIcon />
                </IconButton>
              </Box>
            </DialogTitle>
            <DialogContent dividers>
              <Grid container spacing={3}>
                <Grid item xs={12} md={4}>
                  <Box sx={{ position: 'relative' }}>
                    <img
                      src={selectedDoctor.profilePhoto || selectedDoctor.userId?.profilePhoto || defaultDoctorImage}
                      alt={selectedDoctor.userId?.name}
                      style={{ width: '100%', borderRadius: '8px' }}
                    />
                    <Box sx={{ mt: 2 }}>
                      <Rating value={selectedDoctor.ratings?.overall || 0} readOnly precision={0.5} />
                      <Typography variant="body2" color="text.secondary">
                        {selectedDoctor.ratings?.totalReviews || 0} patient reviews
                      </Typography>
                    </Box>
                  </Box>
                </Grid>
                <Grid item xs={12} md={8}>
                  <Typography variant="h6" color="primary" gutterBottom>
                    {selectedDoctor.specialization}
                  </Typography>
                  <Typography variant="body1" paragraph>
                    {selectedDoctor.bio || `Experienced ${selectedDoctor.specialization} specialist with ${selectedDoctor.experience} years of practice.`}
                  </Typography>
                  <Typography variant="subtitle1" gutterBottom>
                    Speciality
                  </Typography>
                  <Typography variant="body2" color="text.secondary" paragraph>
                    {selectedDoctor.specialityDescription || selectedDoctor.specialization}
                  </Typography>

                  <Grid container spacing={2}>
                    <Grid item xs={6}>
                      <Typography variant="subtitle1">Experience</Typography>
                      <Typography variant="body2" color="text.secondary">
                        {selectedDoctor.experience} years
                      </Typography>
                    </Grid>
                    <Grid item xs={6}>
                      <Typography variant="subtitle1">Consultation Fee</Typography>
                      <Typography variant="body2" color="text.secondary">
                        ₹{selectedDoctor.consultationFee}
                      </Typography>
                    </Grid>
                  </Grid>

                  <Box sx={{ mt: 3 }}>
                    <Typography variant="subtitle1" gutterBottom>
                      Education
                    </Typography>
                    {selectedDoctor.qualifications.map((edu, index) => (
                      <Box key={index} sx={{ mb: 2 }}>
                        <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                          {edu.degree} - {edu.year}
                        </Typography>
                        <Typography variant="body2" color="text.secondary">
                          {edu.institution}
                        </Typography>
                        {edu.honors && (
                          <Typography variant="body2" color="primary">
                            {edu.honors}
                          </Typography>
                        )}
                      </Box>
                    ))}
                  </Box>

                  <Box sx={{ mt: 3 }}>
                    <Typography variant="subtitle1" gutterBottom>
                      Availability Schedule
                    </Typography>
                    {Object.entries(selectedDoctor.availabilitySchedule.regularHours).map(([day, hours]) => (
                      <Box key={day} sx={{ mb: 1 }}>
                        <Typography variant="body2" sx={{ textTransform: 'capitalize' }}>
                          {day}: {hours.morning}, {hours.evening}
                        </Typography>
                      </Box>
                    ))}
                    {selectedDoctor.availabilitySchedule.emergencyAvailable && (
                      <Chip 
                        label="Available for Emergency" 
                        color="error" 
                        size="small" 
                        sx={{ mt: 1 }}
                      />
                    )}
                  </Box>

                  <Box sx={{ mt: 3 }}>
                    <Typography variant="subtitle1" gutterBottom>
                      Languages
                    </Typography>
                    <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
                      {selectedDoctor.languages.map((lang, index) => (
                        <Chip key={index} label={lang} size="small" />
                      ))}
                    </Box>
                  </Box>

                  {selectedDoctor.achievements && selectedDoctor.achievements.length > 0 && (
                    <Box sx={{ mt: 3 }}>
                      <Typography variant="subtitle1" gutterBottom>
                        Achievements
                      </Typography>
                      {selectedDoctor.achievements.map((achievement, index) => (
                        <Box key={index} sx={{ mb: 1 }}>
                          <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                            {achievement.title} ({achievement.year})
                          </Typography>
                          <Typography variant="body2" color="text.secondary">
                            {achievement.description}
                          </Typography>
                        </Box>
                      ))}
                    </Box>
                  )}

                  {selectedDoctor.publications && selectedDoctor.publications.length > 0 && (
                    <Box sx={{ mt: 3 }}>
                      <Typography variant="subtitle1" gutterBottom>
                        Publications
                      </Typography>
                      {selectedDoctor.publications.map((pub, index) => (
                        <Box key={index} sx={{ mb: 1 }}>
                          <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                            {pub.title} ({pub.year})
                          </Typography>
                          <Typography variant="body2" color="text.secondary">
                            {pub.journal}
                          </Typography>
                          {pub.impact && (
                            <Typography variant="body2" color="primary">
                              {pub.impact}
                            </Typography>
                          )}
                        </Box>
                      ))}
                    </Box>
                  )}
                </Grid>
              </Grid>
            </DialogContent>
            <DialogActions>
              <Button onClick={handleCloseDialog}>Close</Button>
              <Button 
                variant="contained" 
                color="primary" 
                onClick={handleBookAppointment}
              >
                Book Appointment
              </Button>
            </DialogActions>
          </>
        )}
      </Dialog>
    </Container>
  );
};

export default Doctors;
